# dnf.map — logical name -> real Fedora/RHEL package(s).
# Only rows where the name actually differs from the logical name (§1); anything
# not listed passes through unchanged (zsh, git, curl, lsd, foot, unzip,
# fontconfig are all identical on dnf, so they need no row).

build = gcc gcc-c++ make
dev-headers = openssl-devel pkgconf-pkg-config
fd = fd-find
